"use client";

import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import * as z from "zod";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";
import { api } from "@/lib/api";
import { useRouter } from "next/navigation";
import { toast } from "sonner";

const loginSchema = z.object({
    username: z.string().email("Invalid email"), // OAuth2 form expects 'username'
    password: z.string().min(1, "Password is required"),
});

export function LoginForm() {
    const router = useRouter();
    const form = useForm<z.infer<typeof loginSchema>>({
        resolver: zodResolver(loginSchema),
    });

    async function onSubmit(values: z.infer<typeof loginSchema>) {
        try {
            const data = await api.auth.login(values);
            localStorage.setItem("token", data.access_token);
            toast.success("Welcome back!");
            router.push("/dashboard");
        } catch (error) {
            toast.error("Invalid credentials.");
        }
    }

    return (
        <Form {...form}>
            <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4">
                <FormField
                    control={form.control}
                    name="username"
                    render={({ field }) => (
                        <FormItem>
                            <FormLabel>Email</FormLabel>
                            <FormControl>
                                <Input placeholder="m@example.com" className="bg-zinc-900 border-zinc-700" {...field} />
                            </FormControl>
                            <FormMessage />
                        </FormItem>
                    )}
                />
                <FormField
                    control={form.control}
                    name="password"
                    render={({ field }) => (
                        <FormItem>
                            <FormLabel>Password</FormLabel>
                            <FormControl>
                                <Input type="password" placeholder="••••••" className="bg-zinc-900 border-zinc-700" {...field} />
                            </FormControl>
                            <FormMessage />
                        </FormItem>
                    )}
                />
                <Button type="submit" className="w-full bg-white text-black hover:bg-zinc-200 mt-2">
                    Login
                </Button>
            </form>
        </Form>
    );
}
